  ('fire-eq-tech-moex-01979', 'fire-eq-tech', 'fire-eq-tech-moex-103-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '懸掛於牆上或放置滅火器箱中之滅火器，其上端與樓地板面之距離為：', '["未滿18公斤者在1.5公尺以下；18公斤以上者在1公尺以下", "未滿18公斤者在1公尺以下；18公斤以上者在1.5公尺以下", "未滿18公斤者在1公尺以下；18公斤以上者在0.5公尺以下", "未滿18公斤者在0.5公尺以下；18公斤以上者在1公尺以下"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "d33f08712e31", "answer_pdf_sha1": "5d173be7ea4b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "402", "s": "0710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "水與化學系統消防安全設備概要", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
